    def numberOfSpecialChars(self, word: str) -> int:
        last_lower = {chr(i + 97): -1 for i in range(26)}
        first_upper = {chr(i + 65): -1 for i in range(26)}

        for i, c in enumerate(word):
            if c.islower():
                last_lower[c] = i
            else:
                if first_upper[c] == -1:
                    first_upper[c] = i

        res = 0
        for i in range(26):
            lc = chr(i + 97)
            uc = chr(i + 65)
            if last_lower[lc] != -1 and first_upper[uc] != -1 and last_lower[lc] < first_upper[uc]:
                res += 1
        return res
